import pickle
from google.cloud import pubsub_v1

def process_batch_job(message):
    try:
        data = pickle.loads(message.data)
        # Process batch job logic here
        print(f"Processed batch job with ID {data['job_id']}")
    except Exception as e:
        print(f"Error processing batch job: {e}")

def pull_messages(project, subscription_name):
    subscriber = pubsub_v1.SubscriberClient()
    subscription_path = subscriber.subscription_path(project, subscription_name)
    
    response = subscriber.pull(subscription_path, max_messages=10)
    messages = []
    
    for message in response.received_messages:
        messages.append(message.message.data.decode('utf-8'))
        
    return messages

def process_batch_jobs(project, subscription_name):
    messages = pull_messages(project, subscription_name)
    
    if messages:
        for message in messages:
            process_batch_job(message)

